import { describe, expect, test } from "vitest";

import {
  certChainBytes,
  decodeRDCleanPath,
  encodeRDCleanPath,
  newRDCleanPathGeneralError,
  newRDCleanPathRequest,
  newRDCleanPathResponse,
  newRDCleanPathTlsError,
  RDCLEAN_PATH_GENERAL_ERROR,
  RDCLEAN_PATH_VERSION_1,
  x224Bytes
} from "./rdcleanpath";

// Reference DER hex captured from the Rust `ironrdp-rdcleanpath` crate.
// Generated by a throwaway binary (see commit message) that called
// RDCleanPathPdu::new_request / new_response / new_general_error /
// new_tls_error and printed the to_der() bytes. If the upstream wire
// format ever changes, regenerate these values.

const SAMPLE_REQUEST_HEX =
  "3048a00402020d3ea2120c107461726765742d686f73743a33333839a3150c136d792d70726f78792d617574682d746f6b656ea6150413030000130ee000000000000100080001000000";

const SAMPLE_REQUEST_X224 = "030000130ee000000000000100080001000000";
const SAMPLE_REQUEST_DEST = "target-host:3389";
const SAMPLE_REQUEST_AUTH = "my-proxy-auth-token";

const SAMPLE_RESPONSE_HEX =
  "3045a00402020d3ea6150413030000130ed000001234000200080002000000a71230100408deadbeef010203040404cafebabea9120c103139322e3136382e312e353a33333839";

const SAMPLE_RESPONSE_X224 = "030000130ed000001234000200080002000000";
const SAMPLE_RESPONSE_CERT0 = "deadbeef01020304";
const SAMPLE_RESPONSE_CERT1 = "cafebabe";
const SAMPLE_RESPONSE_ADDR = "192.168.1.5:3389";

const SAMPLE_GENERAL_ERROR_HEX = "300fa00402020d3ea1073005a003020101";
const SAMPLE_TLS_ERROR_HEX = "3014a00402020d3ea10c300aa003020101a303020130";

const hexToBytes = (hex: string): Uint8Array => {
  const out = new Uint8Array(hex.length / 2);
  for (let i = 0; i < out.length; i += 1) {
    out[i] = parseInt(hex.slice(i * 2, i * 2 + 2), 16);
  }
  return out;
};

const bytesToHex = (bytes: Uint8Array): string => {
  let out = "";
  for (let i = 0; i < bytes.length; i += 1) {
    out += bytes[i].toString(16).padStart(2, "0");
  }
  return out;
};

describe("RDCleanPath codec", () => {
  test("decodes the upstream-generated request", () => {
    const pdu = decodeRDCleanPath(hexToBytes(SAMPLE_REQUEST_HEX));
    expect(pdu.version).toBe(RDCLEAN_PATH_VERSION_1);
    expect(pdu.destination).toBe(SAMPLE_REQUEST_DEST);
    expect(pdu.proxyAuth).toBe(SAMPLE_REQUEST_AUTH);
    expect(pdu.error).toBeUndefined();
    expect(x224Bytes(pdu)).toBeDefined();
    expect(bytesToHex(x224Bytes(pdu)!)).toBe(SAMPLE_REQUEST_X224);
    expect(pdu.serverCertChain).toBeUndefined();
  });

  test("decodes the upstream-generated response", () => {
    const pdu = decodeRDCleanPath(hexToBytes(SAMPLE_RESPONSE_HEX));
    expect(pdu.version).toBe(RDCLEAN_PATH_VERSION_1);
    expect(pdu.destination).toBeUndefined();
    expect(pdu.serverAddr).toBe(SAMPLE_RESPONSE_ADDR);
    expect(bytesToHex(x224Bytes(pdu)!)).toBe(SAMPLE_RESPONSE_X224);
    const certs = certChainBytes(pdu);
    expect(certs).toHaveLength(2);
    expect(bytesToHex(certs[0])).toBe(SAMPLE_RESPONSE_CERT0);
    expect(bytesToHex(certs[1])).toBe(SAMPLE_RESPONSE_CERT1);
  });

  test("decodes the upstream-generated general error", () => {
    const pdu = decodeRDCleanPath(hexToBytes(SAMPLE_GENERAL_ERROR_HEX));
    expect(pdu.error?.errorCode).toBe(RDCLEAN_PATH_GENERAL_ERROR);
    expect(pdu.error?.httpStatusCode).toBeUndefined();
    expect(pdu.error?.wsaLastError).toBeUndefined();
    expect(pdu.error?.tlsAlertCode).toBeUndefined();
  });

  test("decodes the upstream-generated TLS error", () => {
    const pdu = decodeRDCleanPath(hexToBytes(SAMPLE_TLS_ERROR_HEX));
    expect(pdu.error?.errorCode).toBe(RDCLEAN_PATH_GENERAL_ERROR);
    expect(pdu.error?.tlsAlertCode).toBe(48);
  });

  test("encoder matches upstream bytes for a request", () => {
    const pdu = newRDCleanPathRequest({
      destination: SAMPLE_REQUEST_DEST,
      proxyAuth: SAMPLE_REQUEST_AUTH,
      x224ConnectionPdu: hexToBytes(SAMPLE_REQUEST_X224)
    });
    expect(bytesToHex(encodeRDCleanPath(pdu))).toBe(SAMPLE_REQUEST_HEX);
  });

  test("encoder matches upstream bytes for a response", () => {
    const pdu = newRDCleanPathResponse({
      serverAddr: SAMPLE_RESPONSE_ADDR,
      x224ConnectionPdu: hexToBytes(SAMPLE_RESPONSE_X224),
      serverCertChain: [hexToBytes(SAMPLE_RESPONSE_CERT0), hexToBytes(SAMPLE_RESPONSE_CERT1)]
    });
    expect(bytesToHex(encodeRDCleanPath(pdu))).toBe(SAMPLE_RESPONSE_HEX);
  });

  test("encoder matches upstream bytes for general error", () => {
    const pdu = newRDCleanPathGeneralError();
    expect(bytesToHex(encodeRDCleanPath(pdu))).toBe(SAMPLE_GENERAL_ERROR_HEX);
  });

  test("encoder matches upstream bytes for TLS error", () => {
    const pdu = newRDCleanPathTlsError(48);
    expect(bytesToHex(encodeRDCleanPath(pdu))).toBe(SAMPLE_TLS_ERROR_HEX);
  });

  test("round-trips request through encode/decode", () => {
    const original = newRDCleanPathRequest({
      destination: "example.internal:3389",
      proxyAuth: "abc:def",
      x224ConnectionPdu: new Uint8Array([0x03, 0x00, 0x00, 0x13, 0x0e, 0xe0, 0x01])
    });
    const der = encodeRDCleanPath(original);
    const decoded = decodeRDCleanPath(der);
    expect(decoded.destination).toBe(original.destination);
    expect(decoded.proxyAuth).toBe(original.proxyAuth);
    expect(decoded.version).toBe(original.version);
    expect(bytesToHex(x224Bytes(decoded)!)).toBe(bytesToHex(x224Bytes(original)!));
  });
});
